#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    const int prime[13] = {0,0,1,1,0,1,0,1,0,0,0,1}; // index i is 1 if i is prime (2..12)
    while(T--){
        int A,B; scanf("%d %d", &A, &B);
        int sum = A + B;
        if(prime[sum]) printf("Alice\n");
        else printf("Bob\n");
    }
    return 0;
}

