#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    prime = {2,3,5,7,11}
    out = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it))
        out.append('Alice' if A+B in prime else 'Bob')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

